      "words": ["J'ai", "soif", "."],
      "translation": "Ich habe Durst.",
      "explanation": "Bei A1-Sätzen steht das Subjekt (ich, tu, il) vor dem Verb. 'J'ai' ist die erste Person Singular von 'avoir'. 'Soif' bedeutet Durst und wird nach dem Verb gesetzt."
    },
    {
      "words": ["Tu", "as", "mal", "à", "la", "tête", "."],
      "translation": "Du hast Kopfschmerzen.",
      "explanation": "Das Subjekt 'tu' steht vor dem Verb 'as'. Die Präposition 'à la tête' wird verwendet, um den Körperpart zu benennen. Das Adjektiv 'mal' kommt nach dem Verb."
    },
    {
      "words": ["Il", "a", "froid", "."],
      "translation": "Er hat Kälte.",
      "explanation": "Das Subjekt 'il' steht vor dem Verb 'a'. 'Froid' ist ein Adjektiv, das nach dem Verb kommt und sich auf den körperlichen Zustand bezieht."
    },
    {
      "words": ["Elle", "est", "fatiguée", "."],
      "translation": "Sie ist müde.",
      "explanation": "Das Subjekt 'elle' steht vor dem Verb 'est'. Das Adjektiv 'fatiguée' beschreibt den Zustand und folgt unmittelbar nach dem Verb."
    },
    {
      "words": ["Nous", "avons", "soif", "."],
      "translation": "Wir haben Durst.",
      "explanation": "Das Subjekt 'nous' steht vor dem Verb 'avons'. Die Form 'avons' ist die erste Person Plural von 'avoir'. Das Adjektiv 'soif' folgt direkt nach dem Verb."
    }
  ]
